    // Bulk accept all selected offers,

    bulkAcceptOffers: async function () {
        const selectedOffers = store.state.selectedOffers || [];
        if (selectedOffers.length === 0) {
            toast.warning('No offers selected');
            return;
        }
        if (!(await modals.confirm(`Accept ${selectedOffers.length} offer${selectedOffers.length > 1 ? 's' : ''}?`)))
            return;

        store.setState({ offersProcessing: true });
        {
            const el = document.querySelector('.page-content');
            if (el) el.innerHTML = sanitizeHTML(window.pages.offers());
        } // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method

        let successCount = 0;
        let failCount = 0;
        try {
            await api.ensureCSRFToken();

            for (const offerId of selectedOffers) {
                try {
                    await api.post(`/offers/${offerId}/accept`, {});
                    successCount++;
                } catch (error) {
                    console.error(`Failed to accept offer ${offerId}:`, error);
                    failCount++;
                }
            }

            // Update local state
            const offers = store.state.offers.map((o) =>
                selectedOffers.includes(o.id) ? { ...o, status: 'accepted' } : o,
            );
            store.setState({ offers, selectedOffers: [] });

            if (failCount === 0) {
                toast.success(`Accepted ${successCount} offer${successCount > 1 ? 's' : ''}`);
            } else {
                toast.warning(`Accepted ${successCount}, failed ${failCount}`);
            }
            {
                const el = document.querySelector('.page-content');
                if (el) el.innerHTML = sanitizeHTML(window.pages.offers());
            } // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
        } catch (error) {
            console.error('Failed to bulk accept offers:', error);
            toast.error('Failed to process offers: ' + (error.message || 'Unknown error'));
        } finally {
            store.setState({ offersProcessing: false });
        }
    },

