    // Filter automation history by status and type,

    filterAutomationHistory: function () {
        const statusFilter = document.getElementById('history-status-filter')?.value || 'all';
        const typeFilter = document.getElementById('history-type-filter')?.value || 'all';

        const items = document.querySelectorAll('.automation-history-item');
        const dateHeaders = document.querySelectorAll('#automation-history-list > .bg-gray-50');

        items.forEach((item) => {
            const status = item.dataset.status;
            const type = item.dataset.type;

            const statusMatch = statusFilter === 'all' || status === statusFilter;
            const typeMatch = typeFilter === 'all' || type === typeFilter;

            item.style.display = statusMatch && typeMatch ? '' : 'none';
        });

        // Hide date headers if all their items are hidden
        dateHeaders.forEach((header) => {
            const nextItems = [];
            let sibling = header.nextElementSibling;
            while (sibling && !sibling.classList.contains('bg-gray-50')) {
                if (sibling.classList.contains('automation-history-item')) {
                    nextItems.push(sibling);
                }
                sibling = sibling.nextElementSibling;
            }
            const anyVisible = nextItems.some((item) => item.style.display !== 'none');
            header.style.display = anyVisible ? '' : 'none';
        });
    },

