    // Export automation history to CSV,

    exportAutomationHistory: function () {
        if (this._exporting) return;
        this._exporting = true;
        const runs = store.state.automationHistoryRuns || [];
        if (runs.length === 0) {
            this._exporting = false;
            toast.error('No history to export');
            return;
        }

        const headers = [
            'Date',
            'Time',
            'Automation',
            'Status',
            'Duration (s)',
            'Items Processed',
            'Items Succeeded',
            'Items Failed',
            'Message',
        ];
        const rows = runs.map((run) => [
            new Date(run.started_at).toLocaleDateString(),
            new Date(run.started_at).toLocaleTimeString(),
            run.automation_name,
            run.status,
            run.duration_ms ? (run.duration_ms / 1000).toFixed(2) : '',
            run.items_processed || 0,
            run.items_succeeded || 0,
            run.items_failed || 0,
            (run.result_message || run.error_message || '').replace(/,/g, ';'),
        ]);

        const csv = [headers.join(','), ...rows.map((r) => r.join(','))].join('\n');
        const blob = new Blob([csv], { type: 'text/csv' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `automation-history-${toLocalDate(new Date())}.csv`;
        a.click();
        URL.revokeObjectURL(url);

        toast.success('History exported to CSV');
        this._exporting = false;
    },

    // Clear automation history,

    clearAutomationHistory: async function () {
        if (
            !(await modals.confirm('Are you sure you want to clear all automation history? This cannot be undone.', {
                title: 'Clear History',
                confirmText: 'Clear All',
                danger: true,
            }))
        ) {
            return;
        }

        try {
            await api.delete('/automations/history');
            store.setState({ automationHistoryRuns: [] });
            toast.success('History cleared');
            modals.close();
        } catch (error) {
            console.error('Failed to clear history:', error);
            // Clear locally for mock data
            store.setState({ automationHistoryRuns: [] });
            toast.success('History cleared');
            modals.close();
        }
    },

    // Retry a failed automation,

    retryAutomation: async function (runId) {
        const runs = store.state.automationHistoryRuns || [];
        const run = runs.find((r) => r.id === runId);

        if (!run) {
            toast.error('Run not found');
            return;
        }

        toast.info(`Retrying ${run.automation_name}...`);

        try {
            await api.post(`/automations/${run.automation_id || 'default'}/run`);
            toast.success('Automation started');
            handlers.showAutomationHistoryMock();
        } catch (error) {
            toast.error('Failed to start automation: ' + error.message);
        }
    },

