    showDailyReview: function () {
        const tasks = store.state.checklistTasks || store.state.checklistItems || [];
        const today = new Date();
        const todayStr = today.toDateString();

        // Support both camelCase and snake_case property names
        const getCompletedAt = (t) => t.completedAt || t.completed_at || t.last_completed_at;
        const getDueDate = (t) => t.dueDate || t.due_date;

        const completed = tasks.filter((t) => {
            const completedAt = getCompletedAt(t);
            return completedAt && new Date(completedAt).toDateString() === todayStr;
        }).length;

        const total =
            tasks.filter((t) => {
                const dueDate = getDueDate(t);
                return dueDate && new Date(dueDate).toDateString() === todayStr;
            }).length || tasks.length;

        // Calculate weekly data (last 7 days)
        const weeklyData = [];
        const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
        for (let i = 6; i >= 0; i--) {
            const date = new Date(today);
            date.setDate(date.getDate() - i);
            const dateStr = date.toDateString();
            const dayCompleted = tasks.filter((t) => {
                const completedAt = getCompletedAt(t);
                return completedAt && new Date(completedAt).toDateString() === dateStr;
            }).length;
            weeklyData.push({
                day: dayNames[date.getDay()],
                date: date.getDate(),
                completed: dayCompleted,
                isToday: i === 0,
            });
        }

        const maxCompleted = Math.max(...weeklyData.map((d) => d.completed), 1);
        const weeklyTotal = weeklyData.reduce((sum, d) => sum + d.completed, 0);
        const avgPerDay = (weeklyTotal / 7).toFixed(1);

        // Calculate productivity score (mock calculation)
        const productivityScore = Math.min(100, Math.round((weeklyTotal / 35) * 100));
        const getScoreColor = (score) => {
            if (score >= 80) return 'success';
            if (score >= 50) return 'warning';
            return 'error';
        };
        const scoreColor = getScoreColor(productivityScore);

        // Get most productive day
        const mostProductiveDay = weeklyData.reduce(
            (best, day) => (day.completed > best.completed ? day : best),
            weeklyData[0],
        );

        // Calculate streak
        const streakDays = streakCounter.calculate(
            tasks
                .filter((t) => t.completed)
                .map((t) => getCompletedAt(t))
                .filter(Boolean),
        );

        modals.show(
            `
            <div class="modal-header">
                <h2 class="modal-title">Productivity Dashboard</h2>
                <button class="modal-close" aria-label="Close" onclick="modals.close()">${components.icon('close')}</button>
            </div>
            <div class="modal-body">
                <!-- Today's Summary -->
                <div class="daily-review mb-6">
                    <div class="daily-review-celebration">${completed === total && total > 0 ? '🎉' : '📊'}</div>
                    <h3 class="text-xl font-bold mb-2">${completed === total && total > 0 ? 'All tasks complete!' : "Today's Progress"}</h3>
                    <div class="daily-review-stats">
                        <div class="daily-review-stat">
                            <div class="daily-review-stat-value">${completed}</div>
                            <div class="daily-review-stat-label">Completed</div>
                        </div>
                        <div class="daily-review-stat">
                            <div class="daily-review-stat-value">${Math.max(0, total - completed)}</div>
                            <div class="daily-review-stat-label">Remaining</div>
                        </div>
                        <div class="daily-review-stat">
                            <div class="daily-review-stat-value">${total > 0 ? Math.round((completed / total) * 100) : 0}%</div>
                            <div class="daily-review-stat-label">Progress</div>
                        </div>
                    </div>
                </div>

                <!-- Weekly Analytics Section -->
                <div class="weekly-analytics-section">
                    <h3 class="section-title mb-4">${components.icon('bar-chart', 16)} Weekly Analytics</h3>

                    <!-- Weekly Chart -->
                    <div class="weekly-chart-container mb-4">
                        <div class="weekly-chart">
                            ${weeklyData
                                .map(
                                    (d) => `
                                <div class="weekly-chart-bar ${d.isToday ? 'today' : ''}">
                                    <div class="bar-fill" style="height: ${(d.completed / maxCompleted) * 100}%"></div>
                                    <div class="bar-value">${d.completed}</div>
                                    <div class="bar-label">${d.day}</div>
                                </div>
                            `,
                                )
                                .join('')}
                        </div>
                    </div>

                    <!-- Weekly Stats Grid -->
                    <div class="weekly-stats-grid">
                        <div class="weekly-stat-card">
                            <div class="weekly-stat-icon ${scoreColor}">
                                ${components.icon('target', 18)}
                            </div>
                            <div class="weekly-stat-info">
                                <div class="weekly-stat-value">${productivityScore}</div>
                                <div class="weekly-stat-label">Productivity Score</div>
                            </div>
                        </div>
                        <div class="weekly-stat-card">
                            <div class="weekly-stat-icon primary">
                                ${components.icon('check-square', 18)}
                            </div>
                            <div class="weekly-stat-info">
                                <div class="weekly-stat-value">${weeklyTotal}</div>
                                <div class="weekly-stat-label">Tasks This Week</div>
                            </div>
                        </div>
                        <div class="weekly-stat-card">
                            <div class="weekly-stat-icon info">
                                ${components.icon('trending-up', 18)}
                            </div>
                            <div class="weekly-stat-info">
                                <div class="weekly-stat-value">${avgPerDay}</div>
                                <div class="weekly-stat-label">Avg. Per Day</div>
                            </div>
                        </div>
                        <div class="weekly-stat-card">
                            <div class="weekly-stat-icon warning">
                                ${components.icon('zap', 18)}
                            </div>
                            <div class="weekly-stat-info">
                                <div class="weekly-stat-value">${streakDays}</div>
                                <div class="weekly-stat-label">Day Streak</div>
                            </div>
                        </div>
                    </div>

                    <!-- Best Day Highlight -->
                    ${
                        mostProductiveDay.completed > 0
                            ? `
                        <div class="best-day-highlight mt-4">
                            <div class="best-day-icon">⭐</div>
                            <div class="best-day-text">
                                <strong>${mostProductiveDay.day}</strong> was your most productive day with <strong>${mostProductiveDay.completed} tasks</strong> completed!
                            </div>
                        </div>
                    `
                            : ''
                    }
                </div>
            </div>
            <div class="modal-footer">
                <button class="btn btn-secondary" onclick="modals.close()">Close</button>
            </div>
        `,
            'modal-lg',
        );
    },

