    renderSizeComparison: function () {
        const selA = document.getElementById('compare-chart-a');
        const selB = document.getElementById('compare-chart-b');
        const container = document.getElementById('size-comparison-tables');
        if (!selA || !selB || !container) return;

        const renderMiniChart = (tabId) => {
            const data = handlers._getSizeData(tabId);
            if (!data) return '<div style="color: var(--gray-400);">No data</div>';
            let html = `<div style="font-weight: 600; margin-bottom: 6px; font-size: 13px;">${data.title}</div>`;
            html +=
                '<div style="overflow-x: auto;"><table style="width: 100%; border-collapse: collapse; font-size: 11px;">';
            html +=
                '<thead><tr>' +
                data.headers
                    .map(
                        (h) =>
                            `<th style="border: 1px solid var(--gray-200); padding: 4px 6px; background: var(--gray-50); white-space: nowrap;">${h}</th>`,
                    )
                    .join('') +
                '</tr></thead>';
            html +=
                '<tbody>' +
                data.rows
                    .map(
                        (row, i) =>
                            `<tr style="background: ${i % 2 === 0 ? 'white' : 'var(--gray-50)'};">` +
                            row
                                .map(
                                    (c, j) =>
                                        `<td style="border: 1px solid var(--gray-200); padding: 4px 6px; ${j === 0 ? 'font-weight: 600;' : ''}">${c}</td>`,
                                )
                                .join('') +
                            '</tr>',
                    )
                    .join('') +
                '</tbody>';
            html += '</table></div>';
            return html;
        };

        container.innerHTML = sanitizeHTML(
            `<div>${renderMiniChart(selA.value)}</div><div>${renderMiniChart(selB.value)}</div>`,
        ); // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
    },

