    // Multi-Shop Sync Settings handler,

    showMultiShopSyncSettings: function () {
        const shops = (store.state.shops || []).filter((s) => s.is_connected);
        const syncConfig = store.state.shopSyncConfig || {};

        modals.show(`
            <div class="modal-header">
                <h2 class="modal-title">${components.icon('refresh-cw', 20)} Sync Settings</h2>
                <button class="modal-close" aria-label="Close" onclick="modals.close()">${components.icon('x', 20)}</button>
            </div>
            <div class="modal-body">
                <p class="text-sm text-gray-500 mb-4">Configure how inventory syncs between your connected platforms.</p>
                ${shops
                    .map((shop) => {
                        const cfg = syncConfig[shop.platform] || {};
                        return `
                        <div style="padding: 14px; border: 1px solid var(--gray-200); border-radius: 10px; margin-bottom: 12px;">
                            <div class="flex items-center justify-between mb-3">
                                <span class="font-medium">${shop.platform.charAt(0).toUpperCase() + shop.platform.slice(1)}</span>
                                <label class="flex items-center gap-2">
                                    <input aria-label="Enable sync" type="checkbox" class="sync-enabled-check" data-platform="${shop.platform}" ${cfg.enabled !== false ? 'checked' : ''}>
                                    <span class="text-sm">Enabled</span>
                                </label>
                            </div>
                            <div class="grid grid-cols-2 gap-3">
                                <div class="form-group mb-0">
                                    <label class="form-label text-xs">Sync Mode</label>
                                    <select class="form-select form-select-sm sync-mode-select" aria-label="Sync mode" data-platform="${shop.platform}">
                                        <option value="two-way" ${cfg.mode === 'two-way' || !cfg.mode ? 'selected' : ''}>Two-way</option>
                                        <option value="push-only" ${cfg.mode === 'push-only' ? 'selected' : ''}>Push only</option>
                                        <option value="pull-only" ${cfg.mode === 'pull-only' ? 'selected' : ''}>Pull only</option>
                                    </select>
                                </div>
                                <div class="form-group mb-0">
                                    <label class="form-label text-xs">Frequency</label>
                                    <select class="form-select form-select-sm sync-freq-select" aria-label="Sync frequency" data-platform="${shop.platform}">
                                        <option value="realtime" ${cfg.frequency === 'realtime' ? 'selected' : ''}>Real-time</option>
                                        <option value="15min" ${cfg.frequency === '15min' || !cfg.frequency ? 'selected' : ''}>Every 15 min</option>
                                        <option value="hourly" ${cfg.frequency === 'hourly' ? 'selected' : ''}>Hourly</option>
                                        <option value="daily" ${cfg.frequency === 'daily' ? 'selected' : ''}>Daily</option>
                                    </select>
                                </div>
                            </div>
                            <div class="mt-2">
                                <label class="flex items-center gap-2">
                                    <input aria-label="Sync quantity" type="checkbox" class="sync-quantity-check" data-platform="${shop.platform}" ${cfg.syncQuantity !== false ? 'checked' : ''}>
                                    <span class="text-xs text-gray-600">Sync quantity across platforms</span>
                                </label>
                                <label class="flex items-center gap-2 mt-1">
                                    <input aria-label="Sync price" type="checkbox" class="sync-price-check" data-platform="${shop.platform}" ${cfg.syncPrice ? 'checked' : ''}>
                                    <span class="text-xs text-gray-600">Sync price changes across platforms</span>
                                </label>
                            </div>
                        </div>
                    `;
                    })
                    .join('')}
            </div>
            <div class="modal-footer">
                <button class="btn btn-secondary" onclick="modals.close()">Cancel</button>
                <button class="btn btn-primary" onclick="handlers.saveMultiShopSyncSettings()">Save Sync Settings</button>
            </div>
        `);
    },

    saveMultiShopSyncSettings: function () {
        const shops = (store.state.shops || []).filter((s) => s.is_connected);
        const syncConfig = store.state.shopSyncConfig || {};

        shops.forEach((shop) => {
            const p = shop.platform;
            const enabledCheck = document.querySelector(`.sync-enabled-check[data-platform="${p}"]`);
            const modeSelect = document.querySelector(`.sync-mode-select[data-platform="${p}"]`);
            const freqSelect = document.querySelector(`.sync-freq-select[data-platform="${p}"]`);
            const qtyCheck = document.querySelector(`.sync-quantity-check[data-platform="${p}"]`);
            const priceCheck = document.querySelector(`.sync-price-check[data-platform="${p}"]`);

            syncConfig[p] = {
                enabled: enabledCheck?.checked ?? true,
                mode: modeSelect?.value || 'two-way',
                frequency: freqSelect?.value || '15min',
                syncQuantity: qtyCheck?.checked ?? true,
                syncPrice: priceCheck?.checked ?? false,
                lastSync: (syncConfig[p] || {}).lastSync || null,
            };
        });

        store.setState({ shopSyncConfig: syncConfig });
        toast.success('Sync settings saved!');
        modals.close();
        renderApp(window.pages.shops());
    },

