    updateSupplier: function (e, id) {
        e.preventDefault();
        const form = e.target;

        const suppliers =
            store.state.suppliers?.map((s) =>
                s.id === id
                    ? {
                          ...s,
                          name: form.name.value,
                          email: form.email.value,
                          phone: form.phone.value,
                          notes: form.notes.value,
                      }
                    : s,
            ) || [];
        store.setState({ suppliers });
        toast.success('Supplier updated');
        modals.close();
        renderApp(window.pages.suppliers());
    },

    // Feature 1: Search suppliers,

    searchSuppliers: function (query) {
        store.setState({ supplierSearchQuery: query });
        if (store.state.currentPage === 'suppliers') {
            const pageContent = pages.suppliers();
            document.querySelector('.page-content').innerHTML = sanitizeHTML(pageContent); // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
            const input = document.getElementById('supplier-search-input');
            if (input) input.focus();
        }
    },

    // Feature 2: Sort suppliers,

    sortSuppliers: function (sortBy) {
        store.setState({ supplierSortBy: sortBy });
        if (store.state.currentPage === 'suppliers') {
            const pageContent = pages.suppliers();
            document.querySelector('.page-content').innerHTML = sanitizeHTML(pageContent); // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
        }
    },

    confirmDeleteSupplier: function (id) {
        const suppliers = (store.state.suppliers || []).filter((s) => s.id !== id);
        store.setState({ suppliers });
        toast.success('Supplier deleted');
        modals.close();
        renderApp(window.pages.suppliers());
    },

    // Feature 4: Supplier form validation,

    validateSupplierField: function (field, value) {
        const errors = {};
        if (field === 'email' && value.trim()) {
            const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
            if (!emailRegex.test(value)) {
                errors.email = 'Please enter a valid email address';
            }
        }
        if (field === 'phone' && value.trim()) {
            const digitsOnly = value.replace(/\D/g, '');
            if (digitsOnly.length < 7) {
                errors.phone = 'Phone must contain at least 7 digits';
            }
        }
        return errors;
    },

    // Feature 5: Show CSV import modal,

    showSupplierImport: function () {
        modals.show(
            'Import Suppliers from CSV',
            `
            <div style="padding: 16px;">
                <p style="color: var(--gray-600); margin-bottom: 12px; font-size: 12px;">
                    Expected CSV format (comma-separated): <code style="background: var(--gray-100); padding: 4px 8px; border-radius: 4px;">name,website,email,phone,notes</code>
                </p>
                <div class="form-group" style="margin-bottom: 16px;">
                    <label class="form-label" for="csv-import-input">Select CSV File</label>
                    <inputinput type="file" id="csv-import-input" class="form-input" accept=".csv,.txt" onchange="handlers.processSupplierCSV(event)">
                </div>
                <div id="csv-preview" style="margin-bottom: 16px;"></div>
                <div style="display: flex; gap: 8px; justify-content: flex-end;">
                    <button class="btn btn-secondary" onclick="modals.close()">Cancel</button>
                    <button class="btn btn-primary" id="import-suppliers-btn" onclick="handlers.importSuppliers()" style="display: none;">Import All</button>
                </div>
            </div>
        `,
        );
    },

    processSupplierCSV: function (event) {
        const file = event.target.files[0];
        if (!file) return;

        if (file.size > 5 * 1024 * 1024) {
            toast.error('CSV file too large. Maximum 5MB.');
            return;
        }

        const reader = new FileReader();
        reader.onload = (e) => {
            const csv = e.target.result;
            const lines = csv
                .trim()
                .split('\n')
                .filter((line) => line.trim());
            const suppliers = [];

            lines.forEach((line, idx) => {
                const [name, website, email, phone, notes] = line.split(',').map((s) => s.trim());
                if (name && idx > 0) {
                    suppliers.push({
                        id: 'sup_' + Date.now() + '_' + Math.random(),
                        name,
                        website: website || '',
                        email: email || '',
                        phone: phone || '',
                        notes: notes || '',
                        rating: 0,
                        item_count: 0,
                        created_at: new Date().toISOString(),
                    });
                }
            });

            if (suppliers.length === 0) {
                toast.warning('No valid suppliers found in CSV');
                return;
            }

            store.setState({ _csvSuppliers: suppliers });

            const preview = `
                <div>
                    <h3 style="margin-bottom: 8px; color: var(--gray-700);">Preview: ${suppliers.length} suppliers</h3>
                    <div class="table-container" tabindex="0" style="max-height: 300px; overflow-y: auto;">
                        <table class="table" style="font-size: 12px;">
                            <thead>
                                <tr>
                                    <th>Name</th>
                                    <th>Email</th>
                                    <th>Website</th>
                                </tr>
                            </thead>
                            <tbody>
                                ${suppliers
                                    .slice(0, 5)
                                    .map(
                                        (s) => `
                                    <tr>
                                        <td>${escapeHtml(s.name)}</td>
                                        <td>${escapeHtml(s.email)}</td>
                                        <td>${s.website ? '<a href="' + escapeHtml(s.website) + '" target="_blank" style="color: var(--primary);">Visit</a>' : '-'}</td>
                                    </tr>
                                `,
                                    )
                                    .join('')}
                            </tbody>
                        </table>
                    </div>
                    ${suppliers.length > 5 ? `<p style="font-size: 11px; color: var(--gray-500); margin-top: 8px;">...and ${suppliers.length - 5} more</p>` : ''}
                </div>
            `;

            const csvPreviewEl = document.getElementById('csv-preview');
            if (csvPreviewEl) csvPreviewEl.innerHTML = sanitizeHTML(preview); // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
            const importBtn = document.getElementById('import-suppliers-btn');
            if (importBtn) importBtn.style.display = 'block';
        };
        reader.readAsText(file);
    },

    importSuppliers: function () {
        const csvSuppliers = store.state._csvSuppliers || [];
        if (csvSuppliers.length === 0) {
            toast.warning('No suppliers to import');
            return;
        }

        const existing = store.state.suppliers || [];
        const updated = [...existing, ...csvSuppliers];
        store.setState({ suppliers: updated, _csvSuppliers: null });
        toast.success(`${csvSuppliers.length} suppliers imported successfully`);
        modals.close();
        renderApp(window.pages.suppliers());
    },

