    saveMarketAlertConfig: function () {
        const config = {
            price_surge: document.getElementById('alert-price_surge')?.checked ?? true,
            demand_spike: document.getElementById('alert-demand_spike')?.checked ?? true,
            price_drop: document.getElementById('alert-price_drop')?.checked ?? true,
            new_competitor: document.getElementById('alert-new_competitor')?.checked ?? true,
            threshold: parseInt(document.getElementById('alert-threshold')?.value || 10),
            frequency: document.getElementById('alert-frequency')?.value || 'realtime',
        };
        store.setState({ marketAlertConfig: config });
        toast.success('Alert configuration saved');
        modals.close();
    },

    runPriceSuggestion: async function () {
        const itemName = document.getElementById('price-suggest-title')?.value || '';
        const condition = document.getElementById('price-suggest-condition')?.value || 'good';
        const category = document.getElementById('price-suggest-category')?.value || 'general';

        if (!itemName.trim()) {
            toast.error('Please enter an item name');
            return;
        }

        const resultEl = document.getElementById('price-suggestion-result');
        if (resultEl)
            resultEl.innerHTML = sanitizeHTML(
                '<div style="text-align: center; padding: 20px;"><div class="spinner"></div><p style="margin-top: 8px; color: var(--gray-500);">Fetching price data...</p></div>',
            ); // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method

        try {
            const data = await api.post('/ai/suggest-price', { title: itemName, condition, category });
            const { low, suggested, high } = data.priceRange || {};
            const comparableSales = data.comparables?.length ?? null;
            if (resultEl) {
                // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
                resultEl.innerHTML = sanitizeHTML(`
                    <div style="padding: 16px; background: var(--primary-50); border-radius: 8px; border: 1px solid var(--primary-200);">
                        <div style="text-align: center; margin-bottom: 16px;">
                            <div style="font-size: 12px; color: var(--gray-600);">Suggested Price Range</div>
                            <div style="font-size: 32px; font-weight: 700; color: var(--primary-600);">C$${low} – C$${high}</div>
                            <div style="font-size: 14px; color: var(--success); font-weight: 600;">Best Price: C$${suggested}</div>
                        </div>
                        <div style="display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 12px; text-align: center;">
                            <div><div style="font-size: 18px; font-weight: 700;">${comparableSales ?? '—'}</div><div style="font-size: 11px; color: var(--gray-500);">Comparable Sales</div></div>
                            <div><div style="font-size: 18px; font-weight: 700;">${avgDaysToSell != null ? avgDaysToSell + 'd' : '—'}</div><div style="font-size: 11px; color: var(--gray-500);">Avg Sell Time</div></div>
                            <div><div style="font-size: 18px; font-weight: 700;">${data.confidence ?? '—'}${data.confidence != null ? '%' : ''}</div><div style="font-size: 11px; color: var(--gray-500);">Confidence</div></div>
                        </div>
                    </div>
                `);
            }
            toast.success('Price suggestion ready');
        } catch {
            if (resultEl)
                resultEl.innerHTML = sanitizeHTML(
                    '<p style="text-align:center;padding:20px;color:var(--gray-500);">Price intelligence requires connected marketplace data. Connect your accounts to enable AI pricing.</p>',
                ); // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
        }
    },

