    saveSavedSearch: function (e) {
        e.preventDefault();
        const form = e.target;
        const newSearch = {
            id: 'ss_' + Date.now(),
            name: form.name.value,
            query: form.query.value,
            category: form.category.value,
            minPrice: form.minPrice.value ? parseFloat(form.minPrice.value) : null,
            maxPrice: form.maxPrice.value ? parseFloat(form.maxPrice.value) : null,
            alertEnabled: form.alertEnabled.checked,
            lastRun: null,
            results: 0,
            created_at: new Date().toISOString(),
        };

        const savedSearches = [...(store.state.savedSearches || []), newSearch];
        store.setState({ savedSearches });
        toast.success('Saved search "' + newSearch.name + '" created');
        modals.close();
        renderApp(window.pages.marketIntel());
    },

    removeSavedSearch: function (id) {
        const savedSearches = (store.state.savedSearches || []).filter((s) => s.id !== id);
        store.setState({ savedSearches });
        toast.success('Saved search removed');
        renderApp(window.pages.marketIntel());
    },

    runSavedSearch: function (id) {
        const search = (store.state.savedSearches || []).find((s) => s.id === id);
        if (!search) return;

        toast.info('Running search: ' + search.name + '...');
        setTimeout(() => {
            const savedSearches = (store.state.savedSearches || []).map((s) =>
                s.id === id ? { ...s, lastRun: new Date().toISOString(), results: null } : s,
            );
            store.setState({ savedSearches });
            toast.success(
                'Found ' +
                    (savedSearches.find((s) => s.id === id)?.results || 0) +
                    ' results for "' +
                    search.name +
                    '"',
            );
            renderApp(window.pages.marketIntel());
        }, 1200);
    },

