    verifyMfaLogin: async function (e) {
        e.preventDefault();
        const code = e.target.code.value.trim();
        if (code.length !== 6) {
            toast.error('Please enter a 6-digit code');
            return;
        }
        try {
            const data = await api.post('/auth/mfa-verify', {
                mfaToken: store.state.pendingMfaToken,
                code,
            });
            store.setState({
                user: data.user,
                token: data.token,
                refreshToken: data.refreshToken,
                pendingMfaToken: null,
            });
            modals.close();
            router.navigate('dashboard');
            toast.success('Welcome back!');
        } catch (err) {
            toast.error(err.message || 'Invalid verification code');
        }
    },

    verify2FACode: async function (e, method) {
        e.preventDefault();
        const code = e.target.code.value.trim();
        if (code.length !== 6) {
            toast.error('Please enter a 6-digit code');
            return;
        }
        if (method !== 'authenticator') {
            toast.info('SMS two-factor authentication is not yet available.');
            return;
        }
        const setupToken = e.target.setupToken?.value;
        const secret = e.target.secret?.value;
        if (!setupToken || !secret) {
            toast.error('Setup session expired. Please start over.');
            return;
        }
        try {
            const data = await api.post('/security/mfa/verify-setup', { setupToken, code, secret });
            store.setState({ user: { ...store.state.user, mfa_enabled: true } });
            modals.close();
            if (data.backupCodes?.length) {
                modals.show(`
                    <div class="modal-header">
                        <h2 class="modal-title">${components.icon('key', 20)} Save Your Backup Codes</h2>
                        <button class="modal-close" aria-label="Close" onclick="modals.close()">${components.icon('close')}</button>
                    </div>
                    <div class="modal-body">
                        <p style="color: var(--warning); font-weight: 600; margin-bottom: 12px;">Save these codes now — you will not be able to see them again.</p>
                        <div style="background: var(--gray-50); padding: 16px; border-radius: 8px; font-family: monospace; font-size: 14px; line-height: 2; user-select: all;">
                            ${data.backupCodes.map((c) => escapeHtml(c)).join('<br>')}
                        </div>
                        <div class="flex justify-end mt-4">
                            <button class="btn btn-primary" onclick="modals.close()">I've Saved These Codes</button>
                        </div>
                    </div>
                `);
            }
            toast.success('Two-factor authentication enabled!');
            renderApp();
        } catch (err) {
            toast.error(err.message || 'Invalid code. Please try again.');
        }
    },

    resetAppearanceToDefaults: async function () {
        if (
            !(await modals.confirm('Reset all appearance settings to defaults?', {
                title: 'Reset to Defaults',
                confirmText: 'Reset',
                danger: true,
            }))
        )
            return;
        // Reset theme to light
        document.body.classList.remove('dark-mode');
        store.setState({ darkMode: false });
        localStorage.setItem('vaultlister_dark_mode', 'false');

        // Reset accent color to none (amber brand default from :root)
        localStorage.setItem('vaultlister_accent', '');
        themeManager.setAccent('');

        // Reset density to default
        localStorage.setItem('vaultlister_density', 'default');
        if (typeof themeManager.setDensity === 'function') {
            themeManager.setDensity('default');
        }

        // Reset font size to default
        localStorage.setItem('vaultlister_fontsize', 'default');
        if (typeof themeManager.setFontSize === 'function') {
            themeManager.setFontSize('default');
        }

        toast.success('Appearance settings reset to defaults');
        renderApp(window.pages.settings());
    },

