    sendFeatureRequest: async function (e) {
        e.preventDefault();
        const form = e.target;
        const title = form.title.value.trim();
        const category = form.category.value;
        const description = form.description.value.trim();
        const reason = form.reason?.value?.trim() || '';

        if (!title || !description) {
            toast.error('Please fill in the title and description');
            return;
        }

        try {
            await api.ensureCSRFToken();
            if (!document.contains(form)) return; // Modal closed during async gap
            await api.post('/feedback', {
                type: 'feature_request',
                category,
                title,
                description: reason ? `${description}\n\nWhy: ${reason}` : description,
                is_anonymous: false,
            });
            toast.success('Thank you! Your feature request has been submitted.');
            modals.close();
        } catch (error) {
            toast.error(error.message || 'Failed to submit feature request');
        }
    },

    toggleGettingStartedStep: function (stepId) {
        const key = 'vaultlister_getting_started';
        let saved = {};
        try {
            saved = JSON.parse(localStorage.getItem(key) || '{}');
        } catch (e) {
            console.error('Failed to parse getting started steps:', e);
            saved = {};
        }
        saved[stepId] = !saved[stepId];
        localStorage.setItem(key, JSON.stringify(saved));
        store.setState({ gettingStartedSteps: saved });
        if (saved[stepId]) {
            toast.success('Step marked as complete!');
        } else {
            toast.info('Step marked as incomplete');
        }
        renderApp();
    },

    // NOTE: viewArticle is defined earlier (~line 39133) with full article
    // rendering, markdown parsing, and category display via modals.show().

    // Feedback handlers,

    submitQuickFeedback: function (e) {
        e.preventDefault();
        const form = e.target;
        const type = form.feedbackType.value;
        const feedback = form.feedback.value;

        if (!feedback.trim()) {
            toast.error('Please enter your feedback');
            return;
        }

        toast.success('Thank you for your feedback!');
        form.reset();

        // Success animation
        const formCard = form.closest('.card-body');
        if (formCard) {
            const successDiv = document.createElement('div');
            successDiv.className = 'feedback-success-animation';
            successDiv.innerHTML = sanitizeHTML(
                '<svg class="feedback-success-check" viewBox="0 0 52 52"><circle cx="26" cy="26" r="25" fill="none" stroke="var(--success)" stroke-width="2"/><path class="feedback-success-path" fill="none" stroke="var(--success)" stroke-width="3" stroke-linecap="round" d="M14.1 27.2l7.1 7.2 16.7-16.8"/></svg><p>Feedback submitted!</p>',
            ); // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
            formCard.appendChild(successDiv);
            setTimeout(() => {
                if (successDiv.parentNode) successDiv.remove();
            }, 2500);
        }

        // Reset char counter
        const counter = form.parentElement.querySelector('.char-count');
        if (counter) counter.textContent = '0/1000';
    },

    voteSuggestion: function (suggestionId) {
        handlers.voteFeedback(suggestionId, 'up');
    },

    voteFeedback: async function (feedbackId, voteType) {
        try {
            await api.ensureCSRFToken();
            const result = await api.post('/feedback/vote/' + feedbackId, { vote_type: voteType });
            // Update trending suggestions in state
            const trending = store.state.trendingSuggestions || [];
            const idx = trending.findIndex((s) => s.id === feedbackId);
            if (idx >= 0) {
                trending[idx].votes_up = result.votes_up;
                trending[idx].votes_down = result.votes_down;
                trending[idx].user_vote = result.voted ? result.vote_type : null;
                store.setState({ trendingSuggestions: [...trending] });
            }
            toast.success(result.voted ? 'Vote recorded!' : 'Vote removed');
            // Re-render current page
            const currentRoute = store.state.currentPage;
            if (currentRoute === 'feedback-suggestions') {
                renderApp(window.pages.feedbackSuggestions());
            } else if (currentRoute === 'feedback-analytics') {
                renderApp(window.pages.feedbackAnalytics());
            }
        } catch (error) {
            console.error('Error voting:', error);
            toast.error('Failed to vote. Please try again.');
        }
    },

