    // Store reference to avoid accumulation,

    showFilterMenu: function () {
        const menu = document.getElementById('filter-menu');
        if (menu) {
            const isHidden = menu.classList.contains('hidden');
            menu.classList.toggle('hidden');

            // Render active filters when opening the menu
            if (isHidden) {
                handlers.renderActiveFilters();

                // Remove old listener if exists
                if (handlers._filterMenuClickHandler) {
                    document.removeEventListener('click', handlers._filterMenuClickHandler);
                }

                // Add click-outside-to-close handler
                setTimeout(() => {
                    handlers._filterMenuClickHandler = (event) => {
                        const filterButton = event.target.closest('button[onclick*="showFilterMenu"]');
                        if (!menu.contains(event.target) && !filterButton) {
                            menu.classList.add('hidden');
                            document.removeEventListener('click', handlers._filterMenuClickHandler);
                            handlers._filterMenuClickHandler = null;
                        }
                    };
                    document.addEventListener('click', handlers._filterMenuClickHandler);
                }, 0);
            } else {
                // Closing menu, remove listener
                if (handlers._filterMenuClickHandler) {
                    document.removeEventListener('click', handlers._filterMenuClickHandler);
                    handlers._filterMenuClickHandler = null;
                }
            }
        }
    },

    // Item selection,

    selectAll: function (checked) {
        const checkboxes = document.querySelectorAll('tbody input[type="checkbox"]');
        const selected = new Set(store.state.selectedItems);

        // Batch update all selections
        checkboxes.forEach((cb) => {
            cb.checked = checked;
            if (checked) {
                selected.add(cb.value);
            } else {
                selected.delete(cb.value);
            }
        });

        // Single state update instead of n updates
        store.setState({ selectedItems: Array.from(selected) });

        // Update menu visibility
        const menu = document.getElementById('selection-menu');
        const count = document.getElementById('selection-count');
        if (selected.size > 0) {
            menu?.classList.remove('hidden');
            if (count) count.textContent = selected.size;
        } else {
            menu?.classList.add('hidden');
        }
    },

    toggleItemSelection: function (itemId, checked) {
        const selected = new Set(store.state.selectedItems);
        if (checked) {
            selected.add(itemId);
        } else {
            selected.delete(itemId);
        }
        store.setState({ selectedItems: Array.from(selected) });

        const menu = document.getElementById('selection-menu');
        const count = document.getElementById('selection-count');
        if (selected.size > 0) {
            menu?.classList.remove('hidden');
            if (count) count.textContent = selected.size;
        } else {
            menu?.classList.add('hidden');
        }
    },

    clearSelection: function () {
        // Uncheck all checkboxes
        document.querySelectorAll('tbody input[type="checkbox"]').forEach((cb) => (cb.checked = false));
        document.getElementById('select-all-checkbox')?.checked &&
            (document.getElementById('select-all-checkbox').checked = false);

        // Clear state
        store.setState({ selectedItems: [] });

        // Hide menu
        const menu = document.getElementById('selection-menu');
        menu?.classList.add('hidden');

        toast.info('Selection cleared');
    },

    editItem: function (itemId) {
        const item = store.state.inventory.find((i) => i.id === itemId);
        if (!item) {
            toast.error('Item not found');
            return;
        }
        modals.editItem(item);
    },

    // Duplicate an inventory item,

    duplicateItem: async function (itemId) {
        const item = (store.state.inventory || []).find((i) => i.id === itemId);
        if (!item) {
            toast.error('Item not found');
            return;
        }

        try {
            const newItem = { ...item };
            delete newItem.id;
            delete newItem.created_at;
            delete newItem.updated_at;
            newItem.title = `${item.title} (Copy)`;
            newItem.sku = item.sku ? `${item.sku}-COPY` : null;

            const response = await api.post('/inventory', newItem);
            store.setState({ inventory: [...(store.state.inventory || []), response] });
            toast.success('Item duplicated');
            if (response?.id) {
                auditLog.log('create', 'inventory', response.id, { source: 'duplicate', original: itemId });
            }
            router.navigate('inventory');
        } catch (error) {
            toast.error('Failed to duplicate item');
        }
    },

    // Create listing from inventory item,

    createListingFromItem: function (itemId) {
        const item = store.state.inventory.find((i) => i.id === itemId);
        if (!item) {
            toast.error('Item not found');
            return;
        }
        store.setState({ prefillListingItem: item });
        router.navigate('listings');
        setTimeout(() => modals.addListing?.(), 100);
    },

    // Bulk tag items,

    bulkTag: async function (ids) {
        const tag = await modals.prompt('Enter tag to add to all selected items:', {
            title: 'Add Tag',
            placeholder: 'e.g. vintage',
        });
        if (!tag) return;

        try {
            for (const id of ids) {
                const item = store.state.inventory.find((i) => i.id === id);
                if (item) {
                    const tags = JSON.parse(item.tags || '[]');
                    if (!tags.includes(tag)) {
                        tags.push(tag);
                        await api.put(`/inventory/${id}`, { tags: JSON.stringify(tags) });
                        item.tags = JSON.stringify(tags);
                    }
                }
            }
            toast.success(`Tagged ${ids.length} items with "${tag}"`);
            router.navigate('inventory');
        } catch (error) {
            toast.error('Failed to tag items');
        }
    },

    // Export selected items,

    exportSelectedItems: function (ids) {
        const items = store.state.inventory.filter((i) => ids.includes(i.id));
        if (items.length === 0) return;

        const headers = ['Title', 'SKU', 'Brand', 'Size', 'List Price', 'Cost Price', 'Quantity', 'Status'];
        const rows = items.map((item) => [
            item.title,
            item.sku || '',
            item.brand || '',
            item.size || '',
            item.list_price || '',
            item.cost_price || '',
            item.quantity || 1,
            item.status || '',
        ]);

        const csv = [headers.join(','), ...rows.map((r) => r.map((c) => `"${c}"`).join(','))].join('\n');
        const blob = new Blob([csv], { type: 'text/csv' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `inventory-export-${toLocalDate(new Date())}.csv`;
        a.click();
        URL.revokeObjectURL(url);

        toast.success(`Exported ${items.length} items`);
    },

