    quickAddTask: async function (title) {
        if (!title || !title.trim()) {
            toast.error('Please enter a task title');
            return;
        }
        try {
            await api.ensureCSRFToken();
            const response = await api.post('/checklists/items', {
                title: title.trim(),
                priority: 'normal',
                recurringInterval: 'once',
                dueDate: null,
            });
            // Add to local state
            const newItem = {
                id: response.data?.id || Date.now().toString(),
                title: title.trim(),
                priority: 'normal',
                recurring_interval: 'once',
                due_date: null,
                completed: false,
                created_at: new Date().toISOString(),
            };
            store.setState({
                checklistItems: [newItem, ...(store.state.checklistItems || [])],
            });
            toast.success('Task added');
            const pageContent = pages.checklist();
            renderApp(pageContent);
            // Re-focus the input for continuous adding
            setTimeout(() => {
                const input = document.getElementById('quick-add-task-input');
                if (input) input.focus();
            }, 100);
        } catch (error) {
            console.error('Failed to add task:', error);
            toast.error('Failed to add task');
        }
    },

