    // ============================================
    // To-Do List Handlers (Personal Lists)
    // ============================================,

    createTodoList: async function () {
        const name = await modals.prompt('Enter a name for the new list:', {
            title: 'Create List',
            placeholder: 'List name',
        });
        if (!name || !name.trim()) return;

        const todoLists = store.state.todoLists || [{ id: 'default', name: 'My To-Do List', items: [] }];
        const newList = {
            id: 'list_' + Date.now(),
            name: name.trim(),
            items: [],
        };
        todoLists.push(newList);
        store.setState({ todoLists, activeTodoListId: newList.id });
        this.saveTodoListsToStorage();

        if (store.state.currentPage === 'checklist') {
            const pageContent = pages.checklist();
            document.querySelector('.page-content').innerHTML = sanitizeHTML(pageContent); // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
        }
        toast.success('List created!');
    },

    selectTodoList: function (listId) {
        store.setState({ activeTodoListId: listId });
        if (store.state.currentPage === 'checklist') {
            const pageContent = pages.checklist();
            document.querySelector('.page-content').innerHTML = sanitizeHTML(pageContent); // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
        }
    },

    deleteTodoList: async function (listId) {
        if (
            !(await modals.confirm('Delete this list and all its items?', {
                title: 'Delete List',
                confirmText: 'Delete',
                danger: true,
            }))
        )
            return;

        let todoLists = store.state.todoLists || [];
        todoLists = todoLists.filter((l) => l.id !== listId);
        if (todoLists.length === 0) {
            todoLists = [{ id: 'default', name: 'My To-Do List', items: [] }];
        }
        store.setState({ todoLists, activeTodoListId: todoLists[0].id });
        this.saveTodoListsToStorage();

        if (store.state.currentPage === 'checklist') {
            const pageContent = pages.checklist();
            document.querySelector('.page-content').innerHTML = sanitizeHTML(pageContent); // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
        }
        toast.success('List deleted');
    },

    addTodoItem: function (listId, text) {
        const todoLists = store.state.todoLists || [{ id: 'default', name: 'My To-Do List', items: [] }];
        const list = todoLists.find((l) => l.id === listId);
        if (!list) return;

        list.items = list.items || [];
        list.items.push({ text: text.trim(), done: false, createdAt: new Date().toISOString() });
        store.setState({ todoLists });
        this.saveTodoListsToStorage();

        if (store.state.currentPage === 'checklist') {
            const pageContent = pages.checklist();
            document.querySelector('.page-content').innerHTML = sanitizeHTML(pageContent); // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
            // Focus the input again
            setTimeout(() => document.getElementById('todo-quick-add')?.focus(), 100);
        }
    },

    toggleTodoItem: function (listId, itemIndex, done) {
        const todoLists = store.state.todoLists || [];
        const list = todoLists.find((l) => l.id === listId);
        if (!list || !list.items || !list.items[itemIndex]) return;

        list.items[itemIndex].done = done;
        store.setState({ todoLists });
        this.saveTodoListsToStorage();

        if (store.state.currentPage === 'checklist') {
            const pageContent = pages.checklist();
            document.querySelector('.page-content').innerHTML = sanitizeHTML(pageContent); // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
        }
    },

    deleteTodoItem: function (listId, itemIndex) {
        const todoLists = store.state.todoLists || [];
        const list = todoLists.find((l) => l.id === listId);
        if (!list || !list.items) return;

        list.items.splice(itemIndex, 1);
        store.setState({ todoLists });
        this.saveTodoListsToStorage();

        if (store.state.currentPage === 'checklist') {
            const pageContent = pages.checklist();
            document.querySelector('.page-content').innerHTML = sanitizeHTML(pageContent); // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
        }
    },

    saveTodoListsToStorage: function () {
        try {
            localStorage.setItem('vaultlister_todo_lists', JSON.stringify(store.state.todoLists));
        } catch (e) {
            console.error('Failed to save to-do lists:', e);
        }
    },

