    filterSales: function (filterType, value) {
        if (filterType === 'platform') {
            store.setState({ salesPlatformFilter: value });
        } else if (filterType === 'status') {
            store.setState({ salesStatusFilter: value });
        } else if (filterType === 'item') {
            store.setState({ salesItemFilter: value });
        } else if (filterType === 'buyer') {
            store.setState({ salesBuyerFilter: value });
        }

        // Re-render sales page
        if (store.state.currentPage === 'sales') {
            const pageContent = pages.sales();
            document.querySelector('.page-content').innerHTML = sanitizeHTML(pageContent); // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
        }
    },

    // Sales,

    switchFinancialsTab: function (tab) {
        store.setState({ financialsTab: tab });
        if (store.state.currentPage === 'financials') {
            renderApp(window.pages.financials());
        }
    },

    switchFinancialStatementsSubTab: function (subTab) {
        store.setState({ financialStatementsSubTab: subTab });
        if (store.state.currentPage === 'financials') {
            renderApp(window.pages.financials());
        }
    },

    convertCurrency: function () {
        const amount = parseFloat(document.getElementById('currency-amount')?.value || 100);
        const from = document.getElementById('currency-from')?.value || 'CAD';
        const target = document.getElementById('currency-target')?.value || 'CAD';
        // All rates expressed as units per 1 CAD
        const ratesVsCAD = { CAD: 1, USD: 0.7326, EUR: 0.6779, GBP: 0.5826, AUD: 1.1243, JPY: 109.74 };
        const symbols = { CAD: 'C$', USD: '$', EUR: '€', GBP: '£', AUD: 'A$', JPY: '¥' };
        const fromRate = ratesVsCAD[from] || 1;
        const toRate = ratesVsCAD[target] || 1;
        const rate = toRate / fromRate;
        const converted = amount * rate;
        const el = document.getElementById('currency-result');
        if (el) {
            const safeFrom = from.replace(
                /[&<>"']/g,
                (c) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' })[c],
            );
            const safeTarget = target.replace(
                /[&<>"']/g,
                (c) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' })[c],
            );
            el.innerHTML = sanitizeHTML(
                // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
                '<div style="font-size: 24px; font-weight: 700; color: var(--primary-600);">' +
                    (symbols[target] || '') +
                    converted.toFixed(target === 'JPY' ? 0 : 2) +
                    '</div>' +
                    '<div style="font-size: 12px; color: var(--gray-500); margin-top: 4px;">1 ' +
                    safeFrom +
                    ' = ' +
                    rate.toFixed(4) +
                    ' ' +
                    safeTarget +
                    ' (indicative rate)</div>',
            );
        }
    },

