    saveFinancialGoal: function (e) {
        e.preventDefault();
        const form = e.target;
        const newGoal = {
            id: 'goal_' + Date.now(),
            name: form.name.value,
            category: form.category.value,
            target: parseFloat(form.target.value) || 0,
            current: parseFloat(form.current.value) || 0,
            deadline: form.deadline.value || null,
            created_at: new Date().toISOString(),
        };
        const financialGoals = [...(store.state.financialGoals || []), newGoal];
        store.setState({ financialGoals });
        toast.success('Financial goal "' + newGoal.name + '" created');
        modals.close();
        renderApp(window.pages.financials());
    },

