    addPurchaseItem: function () {
        const inventoryOptions = store.state.inventory
            .map((item) => `<option value="${item.id}">${escapeHtml(item.title)} (${item.sku || 'No SKU'})</option>`)
            .join('');

        const itemHtml = `
            <div class="purchase-item grid grid-cols-5 gap-2 mb-2 items-end">
                <div class="form-group col-span-2">
                    <input type="text" name="itemDescription[]" class="form-input" aria-label="Item description" placeholder="Description" required>
                </div>
                <div class="form-group">
                    <select name="itemInventoryId[]" class="form-select" aria-label="Inventory item">
                        <option value="">-- None --</option>
                        ${inventoryOptions}
                    </select>
                </div>
                <div class="form-group">
                    <input type="number" name="itemQuantity[]" class="form-input" aria-label="Item quantity" min="1" value="1" required>
                </div>
                <div class="form-group">
                    <input type="number" name="itemUnitCost[]" class="form-input" aria-label="Unit cost" min="0" step="0.01" required>
                </div>
            </div>
        `;
        document.getElementById('purchase-items').insertAdjacentHTML('beforeend', itemHtml); // nosemgrep: javascript.browser.security.insecure-document-method
    },

    addPurchase: async function (event) {
        event.preventDefault();
        const form = event.target;
        const formData = new FormData(form);

        const descriptions = formData.getAll('itemDescription[]');
        const inventoryIds = formData.getAll('itemInventoryId[]');
        const quantities = formData.getAll('itemQuantity[]');
        const unitCosts = formData.getAll('itemUnitCost[]');

        const items = descriptions.map((desc, i) => ({
            description: desc,
            inventoryId: inventoryIds[i] || null,
            quantity: parseInt(quantities[i]) || 1,
            unitCost: parseFloat(unitCosts[i]) || 0,
        }));

        const purchaseData = {
            vendorName: formData.get('vendorName'),
            purchaseDate: formData.get('purchaseDate'),
            paymentMethod: formData.get('paymentMethod'),
            items: items,
            shippingCost: parseFloat(formData.get('shippingCost')) || 0,
            notes: formData.get('notes'),
        };

        try {
            await api.ensureCSRFToken();
            await api.post('/financials/purchases', purchaseData);
            toast.success('Purchase added successfully');
            modals.close();
            await this.loadPurchases();
            if (store.state.currentPage === 'financials') {
                renderApp(window.pages.financials());
            }
        } catch (error) {
            toast.error('Failed to add purchase: ' + error.message);
        }
    },

    viewPurchase: async function (id) {
        try {
            const data = await api.get(`/financials/purchases/${id}`);
            const purchase = data.purchase;
            const items = data.items || [];

            modals.show(
                `
                <div class="modal-header">
                    <h2>Purchase ${escapeHtml(purchase.purchase_number || 'N/A')}</h2>
                    <button class="modal-close" aria-label="Close" onclick="modals.close()"><span aria-hidden="true">&times;</span></button>
                </div>
                <div class="modal-body">
                    <div class="grid grid-cols-2 gap-4 mb-4">
                        <div><strong>Vendor:</strong> ${escapeHtml(purchase.vendor_name || 'N/A')}</div>
                        <div><strong>Date:</strong> ${new Date(purchase.purchase_date).toLocaleDateString()}</div>
                        <div><strong>Payment:</strong> ${escapeHtml(purchase.payment_method || 'N/A')}</div>
                        <div><strong>Status:</strong> <span class="badge badge-${purchase.status === 'completed' ? 'success' : 'warning'}">${purchase.status}</span></div>
                    </div>
                    <h3 class="font-medium mb-2">Line Items</h3>
                    <table class="data-table">
                        <thead>
                            <tr>
                                <th>Description</th>
                                <th>Linked Item</th>
                                <th>Qty</th>
                                <th>Unit Cost</th>
                                <th>Total</th>
                            </tr>
                        </thead>
                        <tbody>
                            ${items
                                .map(
                                    (item) => `
                                <tr>
                                    <td>${escapeHtml(item.description)}</td>
                                    <td>${escapeHtml(item.inventory_title || 'N/A')}</td>
                                    <td>${item.quantity}</td>
                                    <td>C$${(item.unit_cost || 0).toFixed(2)}</td>
                                    <td>C$${(item.total_cost || 0).toFixed(2)}</td>
                                </tr>
                            `,
                                )
                                .join('')}
                        </tbody>
                    </table>
                    <div class="mt-4 text-right">
                        <div>Shipping: C$${(purchase.shipping_cost || 0).toFixed(2)}</div>
                        <div class="text-lg font-bold">Total: C$${(purchase.total_amount || 0).toFixed(2)}</div>
                    </div>
                    ${purchase.notes ? `<div class="mt-4"><strong>Notes:</strong> ${escapeHtml(purchase.notes)}</div>` : ''}
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" onclick="modals.close()">Close</button>
                </div>
            `,
                { size: 'lg' },
            );
        } catch (error) {
            toast.error('Failed to load purchase details');
        }
    },

