    setStatementPeriodDates: function (period) {
        const now = new Date();
        let start, end;

        switch (period) {
            case 'this-month':
                start = new Date(now.getFullYear(), now.getMonth(), 1);
                end = now;
                break;
            case 'last-month':
                start = new Date(now.getFullYear(), now.getMonth() - 1, 1);
                end = new Date(now.getFullYear(), now.getMonth(), 0);
                break;
            case 'this-quarter': {
                const q = Math.floor(now.getMonth() / 3);
                start = new Date(now.getFullYear(), q * 3, 1);
                end = now;
                break;
            }
            case 'last-quarter': {
                const q = Math.floor(now.getMonth() / 3) - 1;
                const qYear = q < 0 ? now.getFullYear() - 1 : now.getFullYear();
                const qIdx = q < 0 ? 3 : q;
                start = new Date(qYear, qIdx * 3, 1);
                end = new Date(qYear, qIdx * 3 + 3, 0);
                break;
            }
            case 'this-year':
                start = new Date(now.getFullYear(), 0, 1);
                end = now;
                break;
            case 'last-year':
                start = new Date(now.getFullYear() - 1, 0, 1);
                end = new Date(now.getFullYear() - 1, 11, 31);
                break;
            default:
                return;
        }

        const fmt = (d) => toLocalDate(d);
        const startEl = document.getElementById('statements-start');
        const endEl = document.getElementById('statements-end');
        if (startEl) startEl.value = fmt(start);
        if (endEl) endEl.value = fmt(end);
        this.loadFinancialStatements();
    },

    loadFinancialStatements: async function () {
        const start = document.getElementById('statements-start')?.value;
        const end = document.getElementById('statements-end')?.value;

        try {
            const params = new URLSearchParams();
            if (start) params.append('start', start);
            if (end) params.append('end', end);

            const qs = params.toString();

            // Load both statements and P&L in parallel so all tabs have data
            const [stmtData, pnlData] = await Promise.all([
                api.get(`/financials/statements?${qs}`),
                api.get(`/financials/profit-loss?${qs}`),
            ]);

            store.setState({
                financialStatements: stmtData.statements,
                profitLossReport: pnlData.profitLoss,
            });

            if (store.state.currentPage === 'financials') {
                renderApp(window.pages.financials());
            }
        } catch (error) {
            toast.error('Failed to generate statements: ' + error.message);
        }
    },

    loadProfitLoss: async function () {
        const start = document.getElementById('pnl-start')?.value;
        const end = document.getElementById('pnl-end')?.value;

        try {
            const params = new URLSearchParams();
            if (start) params.append('start', start);
            if (end) params.append('end', end);

            const data = await api.get(`/financials/profit-loss?${params.toString()}`);
            store.setState({ profitLossReport: data.profitLoss });
            if (store.state.currentPage === 'financials') {
                renderApp(window.pages.financials());
            }
        } catch (error) {
            toast.error('Failed to generate P&L: ' + error.message);
        }
    },

