    // Save analytics customization settings,

    saveAnalyticsSettings: function (event, tab) {
        event.preventDefault();
        const form = event.target;
        const formData = new FormData(form);

        // Save tab settings
        const analyticsSettings = { ...(store.state.analyticsSettings || {}) };
        analyticsSettings[tab] = {};

        // Get display options (non-tab checkboxes)
        for (const [key, value] of formData.entries()) {
            if (!key.startsWith('tab_')) {
                analyticsSettings[tab][key] = value === 'on';
            }
        }

        // Get hidden tabs
        const hiddenTabs = [];
        const allTabs = [
            'graphs',
            'performance',
            'heatmaps',
            'predictions',
            'reports',
            'ratio-analysis',
            'profitability-analysis',
            'product-analysis',
        ];
        allTabs.forEach((tabId) => {
            if (!formData.has(`tab_${tabId}`)) {
                hiddenTabs.push(tabId);
            }
        });

        store.setState({ analyticsSettings, hiddenAnalyticsTabs: hiddenTabs });

        // Save to localStorage
        localStorage.setItem('vaultlister_analytics_settings', JSON.stringify(analyticsSettings));
        localStorage.setItem('vaultlister_hidden_analytics_tabs', JSON.stringify(hiddenTabs));

        toast.success('Analytics settings saved');
        modals.close();
        renderApp(window.pages.analytics());
    },

