    // Add a new condition row to the automation conditions,

    addAutomationCondition: function () {
        const container = document.getElementById('automation-conditions');
        if (!container) return;
        const row = document.createElement('div');
        row.className = 'condition-row flex items-center gap-2 p-3 bg-gray-50 rounded-lg';
        // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
        row.innerHTML = sanitizeHTML(`
            <select class="form-select" aria-label="Logic operator" style="width: 140px;">
                <option value="and">AND</option>
                <option value="or">OR</option>
            </select>
            <select class="form-select" aria-label="Condition field" style="width: 140px;">
                <option value="if_price_above">If price above</option>
                <option value="if_price_below">If price below</option>
                <option value="if_days_listed">If listed for</option>
                <option value="if_views_below">If views below</option>
                <option value="if_likes_above">If likes above</option>
                <option value="if_category">If category is</option>
            </select>
            <input type="text" class="form-input" aria-label="Condition value" placeholder="Value" style="width: 100px;">
            <button class="btn btn-xs btn-ghost" onclick="handlers.removeAutomationCondition(this)" title="Remove">
                ${components.icon('x', 14)}
            </button>
        `);
        container.appendChild(row);
    },

    // Remove a condition row,

    removeAutomationCondition: function (btn) {
        const row = btn.closest('.condition-row');
        if (row) row.remove();
    },

    // Save automation configuration,

    saveAutomationConfig: function (automationId) {
        // Gather error handling settings
        const onFailure = document.getElementById('automation-on-failure')?.value || 'retry';
        const maxRetries = parseInt(document.getElementById('automation-max-retries')?.value) || 3;
        const retryDelay = parseInt(document.getElementById('automation-retry-delay')?.value) || 60;
        const failureNotify = document.getElementById('automation-failure-notify')?.value || 'toast';

        // Gather conditions
        const conditionRows = document.querySelectorAll('#automation-conditions .condition-row');
        const conditions = Array.from(conditionRows)
            .map((row) => {
                const selects = row.querySelectorAll('select');
                const input = row.querySelector('input[type="text"]');
                if (selects.length === 0) return null;
                return {
                    field: selects[selects.length > 2 ? 1 : 0]?.value,
                    value: input?.value || '',
                    logic: selects.length > 2 ? selects[0].value : 'and',
                    action: selects[selects.length - 1]?.value || 'then',
                };
            })
            .filter(Boolean);

        // Gather sharing config (if present)
        const shareDelay = parseInt(document.getElementById('automation-share-delay')?.value) || 5;
        const maxShares = parseInt(document.getElementById('automation-max-shares')?.value) || 100;
        const shareOrder = document.getElementById('automation-share-order')?.value || 'random';

        // Store config in state
        const configs = store.state.automationConfigs || {};
        configs[automationId] = {
            conditions,
            errorHandling: { onFailure, maxRetries, retryDelay, failureNotify },
            sharingConfig: { shareDelay, maxShares, shareOrder },
            updatedAt: new Date().toISOString(),
        };
        store.setState({ automationConfigs: configs });

        toast.success('Automation configuration saved!');
    },

    createFromPreset: async function (presetId) {
        try {
            await api.ensureCSRFToken();
            await api.post('/automations/from-preset', { presetId });
            toast.success('Automation created!');
            modals.close();
            await handlers.loadAutomations();

            // Re-render automations page to show new rule
            if (store.state.currentPage === 'automations') {
                const pageContent = pages.automations();
                document.querySelector('.page-content').innerHTML = sanitizeHTML(pageContent); // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
            }
        } catch (error) {
            toast.error(error.message);
        }
    },

    // Shops — connectShop/submitShopConnection/disconnectShop/connectOAuth defined in chunk-settings (handlers-settings-account.js)

    _shopsPlaceholder: null,

