    applyTemplate: async function (templateId) {
        try {
            await api.post(`/templates/${templateId}/use`);
            const template = store.state.templates.find((t) => t.id === templateId);
            if (!template) return;

            // Re-open addItem modal first, then populate
            modals.addItem();
            setTimeout(() => {
                const form = document.getElementById('add-item-form');
                if (!form) return;
                if (template.title_pattern) {
                    const el = form.querySelector('[name="title"]');
                    if (el) el.value = template.title_pattern;
                }
                if (template.description_template) {
                    const el = form.querySelector('[name="description"]');
                    if (el) el.value = template.description_template;
                }
                if (template.category) {
                    const el = form.querySelector('[name="category"]');
                    if (el) el.value = template.category;
                }
                if (template.condition_default) {
                    const el = form.querySelector('[name="condition"]');
                    if (el) el.value = template.condition_default;
                }
                if (template.tags && template.tags.length > 0) {
                    const el = form.querySelector('[name="tags"]');
                    if (el) el.value = template.tags.join(', ');
                }
                toast.success('Template applied!');
            }, 150);
        } catch (error) {
            toast.error(error.message);
        }
    },

    saveListingAsTemplate: async function () {
        // Get current form data from add-item-form
        const form = document.getElementById('add-item-form');
        if (!form) {
            toast.error('No listing form found');
            return;
        }

        const formData = new FormData(form);
        const title = formData.get('title') || '';
        const category = formData.get('category') || '';
        const brand = formData.get('brand') || '';
        const description = formData.get('description') || '';
        const condition = formData.get('condition') || '';

        // Show template name prompt
        const templateName = await modals.prompt('Enter a name for this template:', {
            title: 'Save Template',
            defaultValue: `${brand ? brand + ' ' : ''}${category || 'Custom'} Template`,
            placeholder: 'Template name',
        });
        if (!templateName) return;

        // Capture selected platforms
        const platformCheckboxes = form.querySelectorAll(
            '.platform-checkbox:checked, .adv-new-platform-checkbox:checked',
        );
        const platforms = Array.from(platformCheckboxes).map((cb) => cb.value);

        const templateData = {
            name: templateName,
            description: `Template from listing: ${title}`,
            category: category || null,
            titlePattern: title.replace(brand, '{Brand}').replace(category || '', '{Category}') || null,
            descriptionTemplate: description || null,
            tags: [],
            platforms: platforms.length > 0 ? platforms : null,
            pricingStrategy: 'fixed',
            markupPercentage: 0,
            conditionDefault: condition || null,
            isFavorite: false,
        };

        try {
            await api.ensureCSRFToken();
            await api.post('/templates', templateData);
            toast.success(`Template "${templateName}" saved!`);
            await handlers.loadTemplates();
        } catch (error) {
            toast.error('Failed to save template: ' + error.message);
        }
    },

