    // View image details,

    viewImage: async function (imageId) {
        try {
            const image = await api.get(`/image-bank/${imageId}`);
            const cloudName = store.state.cloudinaryCloudName;

            // Show image detail modal
            modals.show(`
                <div class="image-detail-modal">
                    <div class="image-detail-preview">
                        <img src="${image.cloudinary_public_id && cloudName ? `https://res.cloudinary.com/${cloudName}/image/upload/c_limit,w_800/${image.cloudinary_public_id}` : image.file_path}" alt="${escapeHtml(image.title || image.original_filename)}">
                    </div>
                    <div class="image-detail-info">
                        <h3>${escapeHtml(image.title || image.original_filename)}</h3>
                        ${image.description ? `<p>${escapeHtml(image.description)}</p>` : ''}

                        <div class="image-detail-meta">
                            <div><strong>Size:</strong> ${(image.file_size / 1024).toFixed(1)} KB</div>
                            <div><strong>Dimensions:</strong> ${image.width} × ${image.height}</div>
                            <div><strong>Used:</strong> ${image.used_count} time(s)</div>
                            <div><strong>Uploaded:</strong> ${new Date(image.created_at).toLocaleDateString()}</div>
                        </div>

                        ${
                            image.tags && image.tags.length > 0
                                ? `
                            <div class="image-tags">
                                ${image.tags.map((tag) => `<span class="badge">${escapeHtml(tag)}</span>`).join('')}
                            </div>
                        `
                                : ''
                        }

                        <div class="image-used-by-section">
                            <h3 style="display: flex; align-items: center; gap: 6px; margin-bottom: 8px;">
                                ${components.icon('link', 16)} Used In Listings
                            </h3>
                            <div id="image-usage-list">
                                <div class="loading-spinner-sm" style="display: flex; align-items: center; gap: 8px; color: var(--gray-500); font-size: 13px;">
                                    ${components.icon('loader', 14)} Loading usage...
                                </div>
                            </div>
                        </div>

                        <div class="modal-actions">
                            <button class="btn-primary" onclick="handlers.editImage('${image.id}')">
                                ${components.icon('edit')} Edit
                            </button>
                            <button class="btn-secondary" onclick="handlers.downloadImage('${image.id}')">
                                ${components.icon('download')} Download
                            </button>
                            <button class="btn-danger" onclick="handlers.deleteImage('${image.id}')">
                                ${components.icon('trash')} Delete
                            </button>
                        </div>
                    </div>
                </div>
            `);

            // Fetch usage data asynchronously
            try {
                const usageData = await api.get('/image-bank/usage/' + imageId);
                const usageContainer = document.getElementById('image-usage-list');
                if (usageContainer) {
                    const items = usageData.usage || [];
                    if (items.length > 0) {
                        // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
                        usageContainer.innerHTML = sanitizeHTML(
                            items
                                .map(
                                    (item) => `
                            <div class="image-usage-item" role="button" tabindex="0" onclick="modals.close(); router.navigate('inventory/${item.inventory_id}')">
                                ${components.icon('package', 14)}
                                <span>${escapeHtml(item.title)}</span>
                            </div>
                        `,
                                )
                                .join(''),
                        );
                    } else {
                        usageContainer.innerHTML = sanitizeHTML(
                            '<div class="image-usage-empty">Not used in any listings yet</div>',
                        ); // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
                    }
                }
            } catch (err) {
                const usageContainer = document.getElementById('image-usage-list');
                if (usageContainer) {
                    usageContainer.innerHTML = sanitizeHTML(
                        '<div class="image-usage-empty">Could not load usage data</div>',
                    ); // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
                }
            }
        } catch (error) {
            toast.error('Failed to load image: ' + error.message);
        }
    },

