    // Download image,

    downloadImage: async function (imageId) {
        try {
            const images = store.state.imageBankImages || [];
            const image = images.find((img) => img.id === imageId);

            if (!image) {
                toast.error('Image not found');
                return;
            }

            // Create temporary link to trigger download
            const link = document.createElement('a');
            link.href = image.file_path;
            link.download = image.original_filename;
            link.click();

            toast.success('Download started');
        } catch (error) {
            toast.error('Failed to download image: ' + error.message);
        }
    },

    // Delete single image,

    deleteImage: async function (imageId) {
        if (
            !(await modals.confirm('Delete this image? This cannot be undone.', {
                title: 'Delete Image',
                confirmText: 'Delete',
                danger: true,
            }))
        ) {
            return;
        }

        try {
            await api.delete(`/image-bank/${imageId}`);
            toast.success('Image deleted');

            // Close modal if open
            modals.close();

            await handlers.loadImageBank();

            // Re-render page to reflect deletion
            if (store.state.currentPage === 'image-bank') {
                renderApp(window.pages.imageBank());
            }
        } catch (error) {
            toast.error('Failed to delete image: ' + error.message);
        }
    },

    // Set view mode (grid or list),

    setViewMode: function (mode) {
        const scrollY = window.scrollY;
        store.setState({ imageBankViewMode: mode });
        if (store.state.currentPage === 'image-bank') {
            renderApp(window.pages.imageBank());
            window.scrollTo(0, scrollY);
        }
    },

    // Search images,

    searchImages: async function (query) {
        if (!query || query.trim().length === 0) {
            // If empty search, reload all images
            await handlers.loadImageBank();
            return;
        }

        try {
            const result = await api.get('/image-bank/search', { q: query.trim() });
            store.setState({ imageBankImages: result.images || [] });
        } catch (error) {
            toast.error('Search failed: ' + error.message);
        }
    },

