    // Add receipt line item row,

    addReceiptLineItem: function () {
        const container = document.getElementById('receipt-line-items');
        if (!container) return;

        const newRow = document.createElement('div');
        newRow.className = 'receipt-line-item-row';
        // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
        newRow.innerHTML = sanitizeHTML(`
            <input type="text" name="itemDescription" aria-label="Item description" placeholder="Description" class="form-input">
            <input type="number" name="itemQty" value="1" min="1" class="form-input" aria-label="Item quantity" style="width:60px">
            <input type="number" name="itemUnitPrice" step="0.01" aria-label="Unit price" placeholder="0.00" class="form-input" style="width:80px">
            <input type="number" name="itemTotal" step="0.01" aria-label="Item total" placeholder="0.00" class="form-input" style="width:80px">
            <select name="inventoryLink" class="form-select" aria-label="Inventory link" style="width:120px">
                <option value="">Link inventory...</option>
                ${(store.state.inventory || [])
                    .map(
                        (item) =>
                            `<option value="${item.id}">${escapeHtml(item.title?.substring(0, 30) || 'Untitled')}</option>`,
                    )
                    .join('')}
            </select>
            <button type="button" class="btn btn-icon btn-sm btn-ghost" onclick="this.parentElement.remove()" aria-label="Remove tag">
                <span class="icon"><span aria-hidden="true">×</span></span>
            </button>
        `);
        container.appendChild(newRow);
    },

    // Calculate receipt totals from line items,

    calculateReceiptTotals: function () {
        const rows = document.querySelectorAll('.receipt-line-item-row');
        let subtotal = 0;

        rows.forEach((row) => {
            const qty = parseFloat(row.querySelector('[name="itemQty"]')?.value) || 1;
            const unitPrice = parseFloat(row.querySelector('[name="itemUnitPrice"]')?.value) || 0;
            const total = qty * unitPrice;

            const totalInput = row.querySelector('[name="itemTotal"]');
            if (totalInput) totalInput.value = total.toFixed(2);
            subtotal += total;
        });

        const subtotalInput = document.getElementById('receipt-subtotal');
        const totalInput = document.getElementById('receipt-total');

        if (subtotalInput) subtotalInput.value = subtotal.toFixed(2);

        const discount = parseFloat(document.getElementById('receipt-discount')?.value) || 0;
        const shipping = parseFloat(document.getElementById('receipt-shipping')?.value) || 0;

        if (totalInput) {
            totalInput.value = (subtotal + shipping - discount).toFixed(2);
        }
    },

    // ==========================================
    // Batch Photo Processing Handlers
    // ==========================================

    // Set batch photo transformation,

    setBatchPhotoTransformation: function (key, value) {
        const current = store.state.batchPhotoTransformations;
        store.setState({
            batchPhotoTransformations: { ...current, [key]: value },
        });
    },

    // Set batch photo crop preset,

    setBatchPhotoCropPreset: function (preset) {
        const presets = {
            square: { width: 1000, height: 1000 },
            portrait: { width: 800, height: 1000 },
            landscape: { width: 1200, height: 800 },
            ebay: { width: 1600, height: 1600 },
            poshmark: { width: 1080, height: 1080 },
            whatnot: { width: 1280, height: 1280 },
        };

        const dimensions = presets[preset];
        if (dimensions) {
            const current = store.state.batchPhotoTransformations;
            store.setState({
                batchPhotoTransformations: {
                    ...current,
                    cropWidth: dimensions.width,
                    cropHeight: dimensions.height,
                    cropPreset: preset,
                },
            });
        }
    },

    // Clear batch photo crop,

    clearBatchPhotoCrop: function () {
        const current = store.state.batchPhotoTransformations;
        store.setState({
            batchPhotoTransformations: {
                ...current,
                cropWidth: null,
                cropHeight: null,
                cropPreset: null,
            },
        });
    },

    // Create and start batch photo job,

    createBatchPhotoJob: async function () {
        const selectedImages = store.state.selectedImages || [];
        const transformations = store.state.batchPhotoTransformations;

        // Validate transformations
        const hasTransform =
            transformations.removeBackground ||
            transformations.enhance ||
            transformations.upscale ||
            (transformations.cropWidth && transformations.cropHeight);

        if (!hasTransform) {
            toast.error('Please select at least one transformation');
            return;
        }

        try {
            await api.ensureCSRFToken();

            // Create job
            const createResult = await api.post('/batch-photo/jobs', {
                imageIds: selectedImages,
                transformations: {
                    removeBackground: transformations.removeBackground,
                    enhance: transformations.enhance,
                    upscale: transformations.upscale,
                    cropWidth: transformations.cropWidth,
                    cropHeight: transformations.cropHeight,
                },
            });

            const jobId = createResult.job.id;

            // Initialize progress
            store.setState({
                batchPhotoProgress: {
                    jobId,
                    total: selectedImages.length,
                    processed: 0,
                    failed: 0,
                    status: 'starting',
                },
            });

            // Start job
            await api.post(`/batch-photo/jobs/${jobId}/start`);

            // Start polling for progress
            handlers.pollBatchPhotoProgress(jobId);
        } catch (error) {
            toast.error('Failed to start batch job: ' + error.message);
            store.setState({ batchPhotoProgress: null });
        }
    },

    // Apply batch photo preset,

    applyBatchPhotoPreset: function (presetId) {
        const presets = store.state.batchPhotoPresets || [];
        const preset = presets.find((p) => p.id === presetId);

        if (preset && preset.transformations) {
            store.setState({
                batchPhotoTransformations: {
                    removeBackground: preset.transformations.removeBackground || false,
                    enhance: preset.transformations.enhance || false,
                    upscale: preset.transformations.upscale || false,
                    cropWidth: preset.transformations.cropWidth || null,
                    cropHeight: preset.transformations.cropHeight || null,
                    cropPreset: null,
                },
            });

            // Re-render modal
            if (store.state.batchPhotoModalOpen) {
                modals.batchPhoto();
            }
        }
    },

    // Delete batch photo preset,

    deleteBatchPhotoPreset: async function (presetId) {
        if (
            !(await modals.confirm('Delete this preset?', {
                title: 'Delete Preset',
                confirmText: 'Delete',
                danger: true,
            }))
        )
            return;

        try {
            await api.ensureCSRFToken();
            await api.delete(`/batch-photo/presets/${presetId}`);
            toast.success('Preset deleted');
            await handlers.loadBatchPhotoPresets();

            // Re-render modal
            if (store.state.batchPhotoModalOpen) {
                modals.batchPhoto();
            }
        } catch (error) {
            toast.error('Failed to delete preset: ' + error.message);
        }
    },

