    // ============================================
    // Inventory Import Handlers
    // ============================================,

    handleImportDrop: function (event) {
        const file = event.dataTransfer?.files?.[0];
        if (file) handlers.handleImportFile(file);
    },

    handleImportFile: function (file) {
        if (!file) return;

        if (file.size > 50 * 1024 * 1024) {
            toast.error('File too large. Maximum 50MB for imports.');
            return;
        }

        const ext = file.name.split('.').pop().toLowerCase();
        const typeMap = { csv: 'csv', tsv: 'tsv', xlsx: 'excel', xls: 'excel', json: 'json' };
        const sourceType = typeMap[ext];

        if (!sourceType) {
            toast.error('Unsupported file type. Use CSV, TSV, Excel, or JSON.');
            return;
        }

        const reader = new FileReader();
        reader.onload = async function (e) {
            const data = e.target.result;
            try {
                const result = await api.post('/inventory-import/upload', {
                    filename: file.name,
                    source_type: sourceType,
                    data: data,
                    has_header_row: true,
                    name: file.name,
                });
                store.setState({
                    currentImportJob: {
                        id: result.id,
                        preview: result.preview,
                    },
                });
                renderApp(window.pages.inventoryImport());
                toast.success(`Parsed ${result.preview?.total_rows || 0} rows`);
            } catch (err) {
                toast.error('Failed to parse file: ' + err.message);
            }
        };
        reader.readAsText(file);
    },

    startImportFromPaste: async function () {
        const data = document.getElementById('import-paste-area')?.value?.trim();
        if (!data) {
            toast.error('Please paste data or upload a file');
            return;
        }

        const sourceType = document.getElementById('import-source-type')?.value || 'csv';
        const hasHeader = document.getElementById('import-has-header')?.checked !== false;

        try {
            const result = await api.post('/inventory-import/upload', {
                source_type: sourceType,
                data: data,
                has_header_row: hasHeader,
                name: 'Pasted Data',
            });
            store.setState({
                currentImportJob: {
                    id: result.id,
                    preview: result.preview,
                },
            });
            renderApp(window.pages.inventoryImport());
            toast.success(`Parsed ${result.preview?.total_rows || 0} rows`);
        } catch (err) {
            // Fall back to local client-side parser so the UI still advances to Step 2
            try {
                let headers = [];
                let rows = [];
                if (sourceType === 'json') {
                    let parsed;
                    try {
                        parsed = JSON.parse(data);
                    } catch (_) {
                        parsed = null;
                    }
                    if (!Array.isArray(parsed) || parsed.length === 0) {
                        toast.error('Invalid JSON — expected an array of objects');
                        return;
                    }
                    headers = Object.keys(parsed[0]);
                    rows = parsed.map((r) => headers.map((h) => (r[h] != null ? String(r[h]) : '')));
                } else {
                    const delimiter = sourceType === 'tsv' ? '\t' : ',';
                    const lines = data.split(/\r?\n/).filter((l) => l.trim());
                    if (lines.length === 0) {
                        toast.error('No data found');
                        return;
                    }
                    const splitLine = (line) => {
                        const cells = [];
                        let cur = '';
                        let inQuote = false;
                        for (let i = 0; i < line.length; i++) {
                            const ch = line[i];
                            if (ch === '"' && !inQuote) {
                                inQuote = true;
                            } else if (ch === '"' && inQuote && line[i + 1] === '"') {
                                cur += '"';
                                i++;
                            } else if (ch === '"' && inQuote) {
                                inQuote = false;
                            } else if (ch === delimiter && !inQuote) {
                                cells.push(cur);
                                cur = '';
                            } else {
                                cur += ch;
                            }
                        }
                        cells.push(cur);
                        return cells;
                    };
                    if (hasHeader) {
                        headers = splitLine(lines[0]);
                        rows = lines.slice(1).map(splitLine);
                    } else {
                        const firstRow = splitLine(lines[0]);
                        headers = firstRow.map((_, i) => 'Column ' + (i + 1));
                        rows = lines.map(splitLine);
                    }
                }
                if (headers.length === 0) {
                    toast.error('No columns detected');
                    return;
                }
                const cellData = rows;
                store.setState({
                    currentImportJob: {
                        id: null,
                        preview: { headers, rows: [], cell_data: cellData, total_rows: rows.length },
                    },
                });
                renderApp(window.pages.inventoryImport());
                toast.success(`Parsed ${rows.length} rows (offline preview)`);
            } catch (localErr) {
                toast.error('Failed to parse data: ' + err.message);
            }
        }
    },

    downloadImportTemplate: function () {
        const csv =
            'title,description,price,cost,condition,brand,size,color,sku\n"Example Item","Great condition hoodie",25.00,8.00,"Good","Nike","L","Black","SKU-001"';
        const blob = new Blob([csv], { type: 'text/csv' });
        const a = document.createElement('a');
        a.href = URL.createObjectURL(blob);
        a.download = 'vaultlister-import-template.csv';
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(a.href);
        toast.success('Template downloaded');
    },

