    // ============================================
    // Whatnot Live Handlers
    // ============================================,

    viewWhatnotEvent: async function (eventId) {
        try {
            const data = await api.get(`/whatnot/events/${eventId}`);
            if (!data || !data.event) {
                toast.error('Event not found');
                return;
            }
            store.setState({ viewingWhatnotEvent: data.event });
            modals.viewWhatnotEvent(data.event);
        } catch (e) {
            toast.error('Failed to load event');
        }
    },

    saveWhatnotEvent: async function (isEdit = false) {
        const form = document.getElementById('whatnot-event-form');
        if (!form) return;

        const formData = new FormData(form);
        const eventData = {
            title: formData.get('title'),
            description: formData.get('description'),
            start_time: formData.get('start_time'),
            category: formData.get('category'),
            estimated_duration: parseInt(formData.get('duration')) || 60,
            shipping_option: formData.get('shipping'),
            notes: formData.get('notes'),
        };

        if (!eventData.title || !eventData.start_time) {
            toast.error('Title and start time are required');
            return;
        }

        try {
            await api.ensureCSRFToken();
            if (isEdit) {
                const eventId = store.state.editingWhatnotEvent?.id;
                await api.put(`/whatnot/events/${eventId}`, eventData);
                toast.success('Event updated');
            } else {
                await api.post('/whatnot/events', eventData);
                toast.success('Event created');
            }
            modals.close();
            await handlers.loadWhatnotData();
            renderApp(window.pages.whatnotLive());
        } catch (e) {
            toast.error('Failed to save event: ' + e.message);
        }
    },

    deleteWhatnotEvent: async function (eventId) {
        if (
            !(await modals.confirm('Delete this live event?', {
                title: 'Delete Event',
                confirmText: 'Delete',
                danger: true,
            }))
        )
            return;
        try {
            await api.ensureCSRFToken();
            await api.delete(`/whatnot/events/${eventId}`);
            toast.success('Event deleted');
            await handlers.loadWhatnotData();
            renderApp(window.pages.whatnotLive());
        } catch (e) {
            toast.error('Failed to delete event');
        }
    },

    addItemToWhatnotEvent: async function (eventId, inventoryId) {
        try {
            await api.ensureCSRFToken();
            await api.post(`/whatnot/events/${eventId}/items`, { inventory_id: inventoryId });
            toast.success('Item added to event');
            handlers.viewWhatnotEvent(eventId);
        } catch (e) {
            toast.error('Failed to add item');
        }
    },

    removeItemFromWhatnotEvent: async function (eventId, itemId) {
        try {
            await api.ensureCSRFToken();
            await api.delete(`/whatnot/events/${eventId}/items/${itemId}`);
            toast.success('Item removed');
            handlers.viewWhatnotEvent(eventId);
        } catch (e) {
            toast.error('Failed to remove item');
        }
    },

    // ============================================
    // Custom Reports Handlers
    // ============================================,

    createReport: function () {
        store.setState({
            editingReport: { name: '', description: '', widgets: [], date_range: '30d' },
        });
        renderApp(window.pages.reports());
    },

    editReport: async function (reportId) {
        const report = (store.state.customReports || []).find((r) => r.id === reportId);
        if (report) {
            store.setState({ editingReport: { ...report } });
            renderApp(window.pages.reports());
        }
    },

    viewReport: async function (reportId) {
        try {
            const data = await api.get(`/reports/${reportId}`);
            store.setState({ viewingReport: data.report, reportWidgetData: data.widgetData });
            modals.viewReport(data.report, data.widgetData);
        } catch (e) {
            toast.error('Failed to load report');
        }
    },

    addReportWidget: function (type, label, size) {
        const report = store.state.editingReport;
        if (!report) return;
        const widgets = [...(report.widgets || []), { type, label, size, id: 'w-' + Date.now() }];
        store.setState({ editingReport: { ...report, widgets } });
        renderApp(window.pages.reports());
    },

    removeReportWidget: function (index) {
        const report = store.state.editingReport;
        if (!report) return;
        const widgets = [...(report.widgets || [])];
        widgets.splice(index, 1);
        store.setState({ editingReport: { ...report, widgets } });
        renderApp(window.pages.reports());
    },

    saveReport: async function () {
        const report = store.state.editingReport;
        if (!report) return;

        const name = document.getElementById('report-name')?.value?.trim();
        const description = document.getElementById('report-description')?.value?.trim();
        const date_range = document.getElementById('report-date-range')?.value || '30d';

        if (!name) {
            toast.error('Report name is required');
            return;
        }

        const reportData = {
            name,
            description,
            widgets: report.widgets || [],
            date_range,
        };

        try {
            await api.ensureCSRFToken();
            if (report.id) {
                await api.put(`/reports/${report.id}`, reportData);
                toast.success('Report updated');
            } else {
                await api.post('/reports', reportData);
                toast.success('Report created');
            }
            store.setState({ editingReport: null });
            await handlers.loadReportsData();
            renderApp(window.pages.reports());
        } catch (e) {
            toast.error('Failed to save report: ' + e.message);
        }
    },

    deleteReport: async function (reportId) {
        if (
            !(await modals.confirm('Delete this report?', {
                title: 'Delete Report',
                confirmText: 'Delete',
                danger: true,
            }))
        )
            return;
        try {
            await api.ensureCSRFToken();
            await api.delete(`/reports/${reportId}`);
            toast.success('Report deleted');
            await handlers.loadReportsData();
            renderApp(window.pages.reports());
        } catch (e) {
            toast.error('Failed to delete report');
        }
    },

