    clearCache: function () {
        const cacheKeys = Object.keys(localStorage).filter(
            (k) => k.startsWith('cache_') || k.startsWith('vl_cache_') || k.startsWith('search_cache_'),
        );
        cacheKeys.forEach((k) => localStorage.removeItem(k));
        toast.success(`Cache cleared (${cacheKeys.length} entries removed)`);
    },

    clearDrafts: function () {
        const draftKeys = Object.keys(localStorage).filter(
            (k) => k.startsWith('draft_') || k.startsWith('vl_draft_') || k.startsWith('listing_draft_'),
        );
        draftKeys.forEach((k) => localStorage.removeItem(k));
        toast.success(`Drafts cleared (${draftKeys.length} drafts removed)`);
    },

    regenerateAPIKey: function () {
        toast.info('Developer API keys are not yet available. Check the roadmap for updates.');
    },

    copyAPIKey: function () {
        const key = store.state.apiKey || 'vl_••••••••••••••••';
        navigator.clipboard
            .writeText(key)
            .then(() => {
                toast.success('API key copied - clipboard will clear in 30 seconds');
                setTimeout(() => {
                    navigator.clipboard.writeText('').catch(() => {});
                }, 30000);
            })
            .catch(() => {
                toast.error('Failed to copy API key');
            });
    },

