    _renderForecastContent: function (data) {
        if (!data || !data.forecasts) return '<p class="text-gray-500 text-sm text-center py-4">No data available</p>';
        const forecasts = data.forecasts || [];
        const overall = data.overall || {};
        const healthColors = {
            critical: 'var(--error)',
            low: 'var(--warning-600)',
            healthy: 'var(--success)',
            overstocked: 'var(--primary-500)',
            'no-data': 'var(--gray-400)',
        };
        const healthLabels = {
            critical: 'Critical',
            low: 'Low Stock',
            healthy: 'Healthy',
            overstocked: 'Overstocked',
            'no-data': 'No Data',
        };
        return (
            '<div class="grid grid-cols-4 gap-3 mb-4"><div class="card"><div class="card-body text-center py-2"><div class="text-xl font-bold">' +
            (overall.totalActive || 0) +
            '</div><div class="text-xs text-gray-500">Active Items</div></div></div><div class="card"><div class="card-body text-center py-2"><div class="text-xl font-bold">$' +
            Math.round(overall.totalValue || 0).toLocaleString() +
            '</div><div class="text-xs text-gray-500">Inventory Value</div></div></div><div class="card"><div class="card-body text-center py-2"><div class="text-xl font-bold" style="color:var(--error);">' +
            (overall.restockAlerts || 0) +
            '</div><div class="text-xs text-gray-500">Restock Alerts</div></div></div><div class="card"><div class="card-body text-center py-2"><div class="text-xl font-bold" style="color:var(--primary-500);">' +
            (overall.overstocked || 0) +
            '</div><div class="text-xs text-gray-500">Overstocked</div></div></div></div>' +
            '<table class="table table-sm"><thead><tr><th>Category</th><th>Active</th><th>Value</th><th>Monthly Velocity</th><th>Days of Supply</th><th>Health</th><th>Projected Q</th></tr></thead><tbody>' +
            forecasts
                .map((f) => {
                    const hc = healthColors[f.health] || 'var(--gray-400)';
                    return (
                        '<tr><td>' +
                        escapeHtml(f.category) +
                        '</td><td>' +
                        f.active_count +
                        '</td><td>$' +
                        Math.round(f.active_value).toLocaleString() +
                        '</td><td>' +
                        f.monthly_velocity.toFixed(1) +
                        '/mo</td><td style="color:' +
                        hc +
                        ';font-weight:600;">' +
                        (f.days_of_supply != null ? f.days_of_supply + 'd' : '—') +
                        '</td><td><span class="badge" style="background:' +
                        hc +
                        '20;color:' +
                        hc +
                        ';">' +
                        (healthLabels[f.health] || f.health) +
                        '</span></td><td>' +
                        f.projected_quarterly_sales +
                        '</td></tr>'
                    );
                })
                .join('') +
            '</tbody></table>'
        );
    },

