    // --- Task #128: Duration Trends Chart ---
    loadDurationTrends: async function () {
        try {
            const res = await api.get('/automations/duration-trends');
            const data = res.data || res;
            const trends = data.trends || [];
            store.setState({ durationTrends: trends });
            const el = document.getElementById('duration-trends-chart');
            if (el) el.innerHTML = sanitizeHTML(handlers._renderDurationTrendsChart(trends)); // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
        } catch (e) {
            toast.error('Failed to load duration trends');
        }
    },

    _renderDurationTrendsChart: function (trends) {
        if (!trends || trends.length === 0) {
            return '<p class="text-gray-500 text-sm text-center py-4">No duration data yet. Run some automations first.</p>';
        }

        // Group by rule name
        const byName = {};
        trends.forEach((t) => {
            if (!byName[t.name]) byName[t.name] = [];
            byName[t.name].push(t);
        });
        const names = Object.keys(byName).slice(0, 6);
        const colors = [
            'var(--primary-500)',
            'var(--success)',
            'var(--warning-500)',
            'var(--error)',
            '#8b5cf6',
            '#ec4899',
        ];

        // Build SVG line chart per rule
        const width = 600,
            height = 200,
            padL = 55,
            padR = 20,
            padT = 20,
            padB = 40;
        const chartW = width - padL - padR;
        const chartH = height - padT - padB;

        // Collect all days across all rules
        const allDays = [...new Set(trends.map((t) => t.day))].sort();
        const n = allDays.length;
        if (n === 0) return '<p class="text-gray-500 text-sm text-center py-4">No data</p>';

        const allDurations = trends.map((t) => t.avg_duration || 0);
        const maxDur = Math.max(...allDurations, 1);

        function toX(i) {
            return padL + (i / Math.max(n - 1, 1)) * chartW;
        }
        function toY(v) {
            return padT + chartH - (v / maxDur) * chartH;
        }

        const gridLines = [0, 0.25, 0.5, 0.75, 1]
            .map((pct) => {
                const y = padT + pct * chartH;
                const val = maxDur - pct * maxDur;
                return (
                    '<line x1="' +
                    padL +
                    '" y1="' +
                    y +
                    '" x2="' +
                    (width - padR) +
                    '" y2="' +
                    y +
                    '" stroke="var(--gray-200)" stroke-dasharray="4,4"/>' +
                    '<text x="' +
                    (padL - 6) +
                    '" y="' +
                    (y + 4) +
                    '" text-anchor="end" font-size="10" fill="var(--gray-400)">' +
                    Math.round(val) +
                    'ms</text>'
                );
            })
            .join('');

        const xLabels = allDays
            .map(
                (d, i) =>
                    '<text x="' +
                    toX(i) +
                    '" y="' +
                    (height - 8) +
                    '" text-anchor="middle" font-size="9" fill="var(--gray-500)">' +
                    d.slice(5) +
                    '</text>',
            )
            .join('');

        const lines = names
            .map((name, ci) => {
                const pts = byName[name];
                const points = allDays
                    .map((day, i) => {
                        const pt = pts.find((p) => p.day === day);
                        return pt ? toX(i) + ',' + toY(pt.avg_duration || 0) : null;
                    })
                    .filter(Boolean);
                if (points.length < 2) return '';
                return (
                    '<polyline points="' +
                    points.join(' ') +
                    '" fill="none" stroke="' +
                    colors[ci % colors.length] +
                    '" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>'
                );
            })
            .join('');

        const legend =
            '<div class="flex flex-wrap gap-3 mb-2">' +
            names
                .map(
                    (name, ci) =>
                        '<span class="text-xs"><span style="display:inline-block;width:12px;height:3px;background:' +
                        colors[ci % colors.length] +
                        ';vertical-align:middle;margin-right:4px;border-radius:2px;"></span>' +
                        escapeHtml(name) +
                        '</span>',
                )
                .join('') +
            '</div>';

        return (
            legend +
            '<svg viewBox="0 0 ' +
            width +
            ' ' +
            height +
            '" preserveAspectRatio="xMidYMid meet" style="width:100%;height:auto;">' +
            gridLines +
            lines +
            xLabels +
            '</svg>'
        );
    },

    // --- Task #129: Price Suggestions ---
    loadPriceSuggestions: async function () {
        try {
            const res = await api.get('/analytics/price-suggestions');
            const data = res.data || res;
            store.setState({ priceSuggestions: data.suggestions || [] });
            const el = document.getElementById('price-suggestions-content');
            if (el) el.innerHTML = sanitizeHTML(handlers._renderPriceSuggestions(data.suggestions || [])); // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
        } catch (e) {
            toast.error('Failed to load price suggestions');
        }
    },

    _renderPriceSuggestions: function (suggestions) {
        if (!suggestions || suggestions.length === 0) {
            return '<p class="text-gray-500 text-sm text-center py-4">No price suggestions — all items are well-priced or too new to evaluate.</p>';
        }

        return (
            '<div class="flex justify-end mb-2"><button class="btn btn-primary btn-sm" onclick="handlers.applyAllPriceSuggestions()">' +
            components.icon('check', 14) +
            ' Apply All (' +
            suggestions.length +
            ')</button></div>' +
            '<table class="table table-sm"><thead><tr><th>Item</th><th>Age</th><th>Current</th><th>Suggested</th><th>Change</th><th>Reason</th><th></th></tr></thead><tbody>' +
            suggestions
                .slice(0, 20)
                .map((s) => {
                    const isDecrease = (s.price_change || 0) < 0;
                    const changeColor = isDecrease ? 'var(--error)' : 'var(--success)';
                    const changePrefix = isDecrease ? '' : '+';
                    return (
                        '<tr><td class="text-sm" style="max-width:180px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">' +
                        escapeHtml(s.title || '') +
                        '</td>' +
                        '<td>' +
                        (s.days_old || 0) +
                        'd</td>' +
                        '<td>$' +
                        (s.list_price || s.current_price || 0).toFixed(2) +
                        '</td>' +
                        '<td style="font-weight:600;">$' +
                        (s.suggested_price || 0).toFixed(2) +
                        '</td>' +
                        '<td style="color:' +
                        changeColor +
                        ';font-weight:600;">' +
                        changePrefix +
                        'C$' +
                        (s.price_change || 0).toFixed(2) +
                        '</td>' +
                        '<td class="text-xs text-gray-500">' +
                        escapeHtml(s.reason || '') +
                        '</td>' +
                        '<td><button class="btn btn-xs btn-ghost" onclick="handlers.applySinglePriceSuggestion(\'' +
                        s.id +
                        "', " +
                        (s.suggested_price || 0) +
                        ', ' +
                        (s.list_price || s.current_price || 0) +
                        ')">' +
                        components.icon('check', 12) +
                        '</button></td></tr>'
                    );
                })
                .join('') +
            '</tbody></table>' +
            (suggestions.length > 20
                ? '<p class="text-xs text-gray-400 mt-2">Showing 20 of ' + suggestions.length + ' suggestions</p>'
                : '')
        );
    },

